from vex_sdk import VexGuardrail

response_agent = agents.Agent(name='ResponseAgent', tools=['firewall_update'])

@guardrail.escalate(policies=['human-approval-critical'])
def execute_response(action):
    result = response_agent.run(action)
    if 'quarantine' in result.content or 'block_ip' in result.content:
        approval = guardrail.request_human_approval(result)
        if not approval:
            return 'Action blocked: Human approval required.'
    return result

# Usage
outcome = execute_response('Quarantine host 10.0.0.5')

import requests
from vex_sdk import VexCustomGuard

@VexCustomGuard(name='cve-validator')
def validate_cve_advisory(output):
    if 'advisory' in output.content:
        cve_id = extract_cve(output.content)  # Custom extractor
        cve_data = requests.get(f'https://cve.mitre.org/data/api/v5/cve/{cve_id}').json()
        if not matches_official(output.content, cve_data):
            return {'approved': False, 'reason': 'CVE mismatch'}
    return {'approved': True}

guardrail = VexGuardrail(custom_guards=[validate_cve_advisory])

advisory_agent = agents.Agent(name='AdvisoryGenerator')
result = advisory_agent.run('Generate advisory for Log4Shell')
validated = guardrail.validate(result)

if validated.approved:
    print('Advisory published')
else:
    print(f'Blocked: {validated.reason}')
